import{_ as s,c as a,o as r,ag as o}from"./chunks/framework.DVUBUV_u.js";const c=JSON.parse('{"title":"Работа с компонентами и props","description":"","frontmatter":{"title":"Работа с компонентами и props"},"headers":[],"relativePath":"ru/props/general.md","filePath":"ru/props/general.md"}'),n={name:"ru/props/general.md"};function e(i,t,l,p,h,d){return r(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="работа-с-компонентами-и-props" tabindex="-1">Работа с компонентами и props <a class="header-anchor" href="#работа-с-компонентами-и-props" aria-label="Permalink to &quot;Работа с компонентами и props&quot;">​</a></h1><p>Раздел <strong>Props</strong> показывает <strong>дерево экземпляров Vue</strong> на открытой странице: имена компонентов, связь с корневым DOM-элементом и сводку по props. Детальные значения подгружаются при выборе строки; при необходимости их можно изменять и отправлять обратно в приложение (в рамках поддерживаемых сценариев).</p><p>Режим <strong>инспектора по клику</strong>, <strong>избранное</strong> и <strong>чёрный список</strong> описаны на отдельных страницах: <a href="/docs/ru/props/inspect.html">Инспектор</a>, <a href="/docs/ru/props/favorite.html">Избранное</a>, <a href="/docs/ru/props/blacklist.html">Чёрный список</a>.</p><h2 id="верхняя-панель-управления" tabindex="-1">Верхняя панель управления <a class="header-anchor" href="#верхняя-панель-управления" aria-label="Permalink to &quot;Верхняя панель управления&quot;">​</a></h2><h3 id="поиск-по-компонентам" tabindex="-1">Поиск по компонентам <a class="header-anchor" href="#поиск-по-компонентам" aria-label="Permalink to &quot;Поиск по компонентам&quot;">​</a></h3><p>Поле поиска поддерживает несколько режимов. Активные критерии задаются фильтром <strong>Search by</strong> рядом с полем ввода. Те же параметры можно заранее настроить в <strong>Options</strong> соответствующей вкладки.</p><table tabindex="0"><thead><tr><th>Режим</th><th>Назначение</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>по имени компонента</td></tr><tr><td><strong>Label</strong></td><td>по строке <code>label</code> / подходящим метаданным инстанса</td></tr><tr><td><strong>Root</strong></td><td>по сведениям о корневом элементе</td></tr><tr><td><strong>Key</strong></td><td>по именам props (в т.ч. вложенным), с углублённым поиском на стороне страницы</td></tr><tr><td><strong>Value</strong></td><td>по значениям props (в т.ч. вложенным), также через запрос к странице</td></tr></tbody></table><p>Для режимов <strong>Key</strong> и <strong>Value</strong> действует минимальная длина запроса (по умолчанию <strong>2</strong> символа; порог настраивается в параметрах поиска инспектора).</p><p><strong>Частичное и точное совпадение.</strong> Если запрос <strong>не</strong> обёрнут в кавычки, по включённым текстовым режимам используется <strong>подстрока</strong> (без учёта регистра). <strong>Точное</strong> совпадение со всей строкой включается, если <strong>весь</strong> текст в поле поиска обёрнут в <strong>двойные кавычки</strong> <code>&quot;...&quot;</code>.</p><p>Рядом с поиском доступна кнопка <strong>Inspect</strong> — выбор узла на странице для фильтрации списка; см. <a href="/docs/ru/props/inspect.html">Инспектор</a>.</p><h3 id="индикаторы-состояния" tabindex="-1">Индикаторы состояния <a class="header-anchor" href="#индикаторы-состояния" aria-label="Permalink to &quot;Индикаторы состояния&quot;">​</a></h3><p>Справа на панели <strong>Props</strong> отображаются вспомогательные элементы:</p><table tabindex="0"><thead><tr><th>Элемент</th><th>Назначение</th></tr></thead><tbody><tr><td><strong>Filtered</strong> (янтарный бейдж)</td><td>Активен фильтр по элементу с страницы (<strong>Inspect</strong>). Клик сбрасывает фильтр и возвращает полный список.</td></tr><tr><td><strong>N</strong> или <strong>N/M</strong></td><td>Число видимых строк после фильтра; при непустом поиске через дробь — общее число компонентов в текущем снимке.</td></tr><tr><td><strong>Избранное</strong> ★</td><td>Число совпавших с текущим деревом записей избранного. Клик открывает раздел <strong>Options</strong> с избранным.</td></tr><tr><td><strong>Обновление</strong></td><td>Кнопка <strong>Refresh</strong> и время последнего обновления снимка (<code>lastUpdated</code>).</td></tr></tbody></table><h2 id="рабочая-область" tabindex="-1">Рабочая область <a class="header-anchor" href="#рабочая-область" aria-label="Permalink to &quot;Рабочая область&quot;">​</a></h2><h3 id="список-компонентов" tabindex="-1">Список компонентов <a class="header-anchor" href="#список-компонентов" aria-label="Permalink to &quot;Список компонентов&quot;">​</a></h3><p>Слева отображается таблица компонентов. Основные колонки (набор можно включать и выключать в настройках таблицы):</p><ul><li><strong>Name</strong> — имя компонента;</li><li><strong>Root Element</strong> — информация о корневом DOM-элементе инстанса (тег, классы, id и т.д., если доступны);</li><li><strong>Received</strong> — число фактически переданных props;</li><li><strong>Declared</strong> — число объявленных в компоненте props.</li></ul><p>При наведении на строку в страницу отправляется подсветка соответствующего узла (чтобы визуально сопоставить строку таблицы с элементом в DOM).</p><p>Через контекстное меню и звезду доступны действия, связанные с <a href="/docs/ru/props/favorite.html">избранным</a> и <a href="/docs/ru/props/blacklist.html">чёрным списком</a>.</p><h3 id="детализация-компонента" tabindex="-1">Детализация компонента <a class="header-anchor" href="#детализация-компонента" aria-label="Permalink to &quot;Детализация компонента&quot;">​</a></h3><p>При выборе строки справа открывается панель с:</p><ul><li>сводной информацией об инстансе;</li><li>представлением <strong>props</strong> (текстовый или древовидный JSON в соответствии с настройками редактора);</li><li>действиями <strong>обновить данные</strong> и (где поддерживается) <strong>редактирование</strong> с сохранением в приложение.</li></ul><p>Звезда <strong>избранного</strong> в этой панели и в таблице описана на странице <a href="/docs/ru/props/favorite.html">Избранное</a>.</p><h2 id="ограничения-отображения" tabindex="-1">Ограничения отображения <a class="header-anchor" href="#ограничения-отображения" aria-label="Permalink to &quot;Ограничения отображения&quot;">​</a></h2><h3 id="ограничения-чтения-данных" tabindex="-1">Ограничения чтения данных <a class="header-anchor" href="#ограничения-чтения-данных" aria-label="Permalink to &quot;Ограничения чтения данных&quot;">​</a></h3><p><strong>Props по запросу:</strong> при открытии карточки компонента значения читаются и сериализуются для панели деталей; для тяжёлых объектов действуют ограничения сериализатора (см. ниже).</p><p>В лёгком списке таблицы передаются метаданные и счётчики без полной сериализации каждого значения на каждом обновлении.</p><h3 id="ограничение-объема-хранения" tabindex="-1">Ограничение объёма хранения <a class="header-anchor" href="#ограничение-объема-хранения" aria-label="Permalink to &quot;Ограничение объёма хранения&quot;">​</a></h3><p>Явного лимита «N записей как в Network» у вкладки <strong>Props</strong> нет: размер данных определяется числом компонентов на странице и политикой кэшей на стороне внедрённого сценария (очистка снимков для экономии памяти применяется там, где узел не раскрыт и не нужен).</p><p>Чтобы не блокировать основной поток страницы, при разборе props действуют ограничения, среди прочего:</p><ul><li>бюджет времени на один проход сериализации;</li><li>максимальная глубина вложенности и размер массивов/объектов;</li><li>усечение длинных строк и общий лимит числа узлов в одном ответе.</li></ul><p>Очень большие или циклические структуры могут отображаться не полностью или с пометкой об усечении — это ожидаемое поведение защиты.</p><h2 id="принципы-работы" tabindex="-1">Принципы работы <a class="header-anchor" href="#принципы-работы" aria-label="Permalink to &quot;Принципы работы&quot;">​</a></h2><h3 id="когда-начинается-сбор-данных" tabindex="-1">Когда начинается сбор данных <a class="header-anchor" href="#когда-начинается-сбор-данных" aria-label="Permalink to &quot;Когда начинается сбор данных&quot;">​</a></h3><p>Модуль Props подключается <strong>после обнаружения Vue</strong> на странице (в отличие от <strong>Network</strong>, который стартует вместе с общим сценарием инспектора). Пока приложение не инициализировало Vue или сценарий инспектора не внедрён в вкладку, список компонентов будет пустым.</p><p>После первой успешной загрузки дерево можно обновлять вручную (<strong>Refresh</strong>) или по расписанию (<strong>автообновление</strong> в <strong>Options</strong>).</p><h3 id="что-попадает-в-мониторинг" tabindex="-1">Что попадает в мониторинг <a class="header-anchor" href="#что-попадает-в-мониторинг" aria-label="Permalink to &quot;Что попадает в мониторинг&quot;">​</a></h3><ol><li><strong>Структура</strong> — обход инстансов Vue даёт плоский список компонентов с метаданными (имя, метка при наличии, привязка к элементу, счётчики переданных и объявленных props без полной сериализации каждого значения на каждом кадре).</li><li><strong>Props по выбору</strong> — полные значения запрашиваются при открытии карточки (ленивая загрузка).</li></ol><p>Через тот же канал панель запрашивает обновлённый список после <strong>Refresh</strong>, с учётом активного <strong>чёрного списка</strong> (фильтрация имён выполняется на стороне сбора данных — подробнее на странице <a href="/docs/ru/props/blacklist.html">Чёрный список</a>).</p><h3 id="как-устроен-обмен" tabindex="-1">Как устроен обмен <a class="header-anchor" href="#как-устроен-обмен" aria-label="Permalink to &quot;Как устроен обмен&quot;">​</a></h3><p>Панель не обращается напрямую к памяти Vue: она отправляет сообщение в контекст страницы, а инъецированный код обходит инстансы и отдаёт сериализованный результат.</p><p>Упрощённо цикл выглядит так:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Иллюстрация: UI запрашивает список компонентов; на странице сканер собирает структуру.</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> response</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bridge.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">send</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  type: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;COLLECT_VUE_COMPONENTS&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  forceRefresh: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  blacklist: { active: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;SomeNoise&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], inactive: [] },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// response.components — имена, uid, счётчики props, строки для Root Element…</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Полные значения props запрашиваются отдельно при открытии карточки (ленивая загрузка).</span></span></code></pre></div><p>Так отделяется <strong>лёгкий список</strong> для таблицы от <strong>тяжёлого чтения props</strong> только для выбранного узла.</p><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/docs/ru/props/inspect.html">Инспектор — выбор компонента с страницы</a></li><li><a href="/docs/ru/props/favorite.html">Избранное</a></li><li><a href="/docs/ru/props/blacklist.html">Чёрный список</a></li><li><a href="/docs/ru/options/update_settings.html">Параметры обновления и автообновление</a> (раздел <strong>Options</strong>)</li></ul>`,46)])])}const k=s(n,[["render",e]]);export{c as __pageData,k as default};
